import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible, selectedCredential, username, apiToken }) {
  const [domain, setDomain] = useState(selectedCredential?.domain || '');  // Initialize domain state with selectedCredential domain
  const [project, setProject] = useState('');  // Initialize project state
  const [issueType, setIssueType] = useState('');  // Initialize issueType state
  const [jiraData, setJiraData] = useState([]);  // Holds the fetched Jira stories
  const [loading, setLoading] = useState(false);  // Loading state
  const [error, setError] = useState(null);  // Error state

  // Update domain whenever selectedCredential changes
  useEffect(() => {
    if (selectedCredential && selectedCredential.domain !== domain) {
      setDomain(selectedCredential.domain);  // Set the domain from the selectedCredential prop
    }
  }, [selectedCredential, domain]);

  // Function to fetch Jira data based on selected filters
  const fetchJiraData = async () => {
    setLoading(true);
    setError(null);

    // Ensure all required fields are provided before making the request
    if (!domain || !project || !issueType || !username || !apiToken) {
      setError("Please provide all required fields: Domain, Project, Issue Type, Username, and API Token.");
      setLoading(false);
      return;
    }

    // Log the constructed URL for debugging
    const url = `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${encodeURIComponent(domain)}&project=${encodeURIComponent(project)}&issueType=${encodeURIComponent(issueType)}&username=${encodeURIComponent(username)}&apiToken=${encodeURIComponent(apiToken)}`;
    console.log('Request URL:', url);  // Debug log for checking URL

    try {
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error('Failed to fetch Jira data.');
      }

      const data = await response.json();
      setJiraData(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // Handle click on a user story
  const handleUserStoryClick = (story) => {
    onSelectUserStory(story);  // Pass the selected story back to the parent component
  };

  // Clear the fetched user stories
  const handleClearJiraData = () => {
    setJiraData([]);
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title"><strong>Fetch Jira User Stories</strong></div>

      <div className="input-fields">
        <p>Domain</p>
        <input
          type="text"
          placeholder="Domain"
          value={domain}
          onChange={(e) => setDomain(e.target.value)}  // Set domain
        />
        <p>Project</p>
        <input
          type="text"
          placeholder="Project"
          value={project}
          onChange={(e) => setProject(e.target.value)}  // Set project
        />
        <p>Issue Type</p>
        <input
          type="text"
          placeholder="Issue Type"
          value={issueType}
          onChange={(e) => setIssueType(e.target.value)}  // Set issueType
        />
        
        <div className="button-container">
          <button onClick={fetchJiraData} disabled={loading}>
            {loading ? 'Fetching...' : 'Fetch Data'}
          </button>
          <button className="clear-button" onClick={handleClearJiraData}>
            Clear Data
          </button>
        </div>
      </div>

      {loading && <div>Loading...</div>}
      {error && <div className="error">{error}</div>}

      <div className="jira-stories">
        {jiraData && jiraData.length > 0 ? (
          jiraData.map((story, index) => (
            <div
              key={index}
              onClick={() => handleUserStoryClick(story)} // Pass selected story to parent
              className="jira-story-box"
            >
              <h4>{story.summary}</h4>
              <p><strong>Assignee:</strong> {story.reporter}</p>
              <p><strong>Description:</strong> {story.description}</p>
            </div>
          ))
        ) : (
          !loading && <div>No stories found.</div>
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
